    SELECT ?item (MAX(?observed_lifespan) AS ?max_lifespan) WHERE {
      ?item wdt:P4214 ?observed_lifespan .
      ?item wdt:P4743 wd:Q3947 .
    } GROUP BY ?item
  }
  FILTER(NOT(?lifespan = ?max_lifespan))
  {
    SELECT ?item (MAX(?observed_lifespan) AS ?second_max_lifespan) WHERE {
      ?item wdt:P4214 ?observed_lifespan .
      ?item wdt:P4743 wd:Q3947 .
      FILTER(?observed_lifespan < (MAX(?observed_lifespan)))
    } GROUP BY ?item
  }
  FILTER(?lifespan = ?second_max_lifespan)
}

